//! encode-and-upload-rknots — embed saturation bitmasks in .rknot and upload
//!
//! Takes pre-computed saturation bitmasks (from profile-saturation-all-models) and embeds
//! them in .rknot metadata, then uploads to cloud storage.
//!
//! USAGE:
//!   cargo run --release --bin encode-and-upload-rknots -- \
//!     --model phi3 \
//!     --saturation-maps /tmp/saturation-output/saturation-maps-phi3_mini.rs \
//!     --knot-input /path/to/phi3-mini.knot \
//!     --knot-output /tmp/phi3-mini-with-saturation.rknot \
//!     --upload-s3  # optional: upload to S3

use std::env;
use std::fs;
use std::path::Path;
use std::time::Instant;

// Model configurations (same as profiler)
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Model {
    Phi3,
    Gemma4,
    Qwen,
    Llama,
}

impl Model {
    fn from_str(s: &str) -> Result<Self, String> {
        match s.to_lowercase().as_str() {
            "phi3" => Ok(Model::Phi3),
            "gemma4" => Ok(Model::Gemma4),
            "qwen" => Ok(Model::Qwen),
            "llama" => Ok(Model::Llama),
            _ => Err(format!("Unknown model: {}", s)),
        }
    }

    fn name(&self) -> &'static str {
        match self {
            Model::Phi3 => "phi3-mini",
            Model::Gemma4 => "gemma4-31b",
            Model::Qwen => "qwen2.5-7b",
            Model::Llama => "llama-70b",
        }
    }

    fn num_layers(&self) -> usize {
        match self {
            Model::Phi3 => 32,
            Model::Gemma4 => 32,
            Model::Qwen => 24,
            Model::Llama => 80,
        }
    }
}

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    let mut model: Option<Model> = None;
    let mut saturation_maps_path: Option<String> = None;
    let mut knot_input: Option<String> = None;
    let mut knot_output: Option<String> = None;
    let mut upload_s3 = false;
    let mut upload_cf_r2 = false;

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--model" => {
                i += 1;
                if i >= args.len() {
                    return Err("--model requires a value".to_string());
                }
                model = Some(Model::from_str(&args[i])?);
            }
            "--saturation-maps" => {
                i += 1;
                if i >= args.len() {
                    return Err("--saturation-maps requires a path".to_string());
                }
                saturation_maps_path = Some(args[i].clone());
            }
            "--knot-input" => {
                i += 1;
                if i >= args.len() {
                    return Err("--knot-input requires a path".to_string());
                }
                knot_input = Some(args[i].clone());
            }
            "--knot-output" => {
                i += 1;
                if i >= args.len() {
                    return Err("--knot-output requires a path".to_string());
                }
                knot_output = Some(args[i].clone());
            }
            "--upload-s3" => upload_s3 = true,
            "--upload-cf-r2" => upload_cf_r2 = true,
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    let model = model.ok_or_else(|| "missing --model".to_string())?;
    let saturation_maps_path =
        saturation_maps_path.ok_or_else(|| "missing --saturation-maps path".to_string())?;
    let knot_output = knot_output.ok_or_else(|| "missing --knot-output path".to_string())?;

    println!("[encode] Processing {} model", model.name());
    let start = Instant::now();

    // Verify saturation maps file exists
    if !Path::new(&saturation_maps_path).exists() {
        return Err(format!(
            "Saturation maps file not found: {}",
            saturation_maps_path
        ));
    }

    // If knot-input provided, load real model weights
    // Otherwise, create synthetic .rknot with saturation metadata only
    let has_input = knot_input.is_some();

    if has_input {
        println!(
            "[encode] Loading input .knot: {}",
            knot_input.as_ref().unwrap()
        );
        let input_path = knot_input.as_ref().unwrap();
        if !Path::new(input_path).exists() {
            return Err(format!("Input knot file not found: {}", input_path));
        }
        // TODO: Load input knot, embed saturation metadata, write output
        println!("[encode] (TODO: implement real .knot embedding)");
    } else {
        println!("[encode] Creating synthetic .rknot with saturation metadata");
    }

    // For now, output a manifest showing what would be embedded
    let manifest_path = knot_output.replace(".rknot", ".saturation-manifest.json");
    let manifest = format!(
        r#"{{
  "model": "{}",
  "num_layers": {},
  "saturation_maps_source": "{}",
  "status": "ready_for_encoding",
  "next_steps": [
    "Load real model weights from knot file",
    "Embed saturation metadata in .rknot header",
    "Upload to cloud storage (S3/CF R2)"
  ]
}}"#,
        model.name(),
        model.num_layers(),
        saturation_maps_path
    );

    fs::write(&manifest_path, manifest).map_err(|e| format!("Failed to write manifest: {}", e))?;

    println!("[encode] Saturation metadata prepared for {}", model.name());
    println!("[encode] Manifest: {}", manifest_path);
    println!("[encode] Output .rknot path (ready): {}", knot_output);

    if upload_s3 {
        println!("[encode] --upload-s3 flag set (TODO: implement S3 upload)");
        println!("[encode] Configure AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, S3_BUCKET");
    }

    if upload_cf_r2 {
        println!("[encode] --upload-cf-r2 flag set (TODO: implement CF R2 upload)");
        println!(
            "[encode] Configure CF_R2_ACCOUNT_ID, CF_R2_ACCESS_KEY, CF_R2_SECRET, CF_R2_BUCKET"
        );
    }

    println!(
        "[encode] Completed in {:.2}s",
        start.elapsed().as_secs_f32()
    );

    Ok(())
}
